public class Rotate {
    static void rotateLeft(int[] arr) {
        int first = arr[0];
        for (int i = 0; i < arr.length - 1; i++) {
            arr[i] = arr[i + 1];
        }
        arr[arr.length - 1] = first;
    }
    public static void main(String[] args) {
        int[] data = {10, 20, 30, 40, 50};
        rotateLeft(data);
        for (int x : data) System.out.print(x + " ");
        System.out.println();
        rotateLeft(data);
        System.out.println(data[0]);
    }
}
